const resp = $input.first().json.content[0].text;
let msgs;
try { msgs = JSON.parse(resp); } catch(e) { const m = resp.match(/\{[\s\S]*\}/); msgs = m ? JSON.parse(m[0]) : { whatsapp: resp, email_assunto: 'Parabens!', email_corpo: resp }; }
const data = $('Webhook - Cliente Contemplado').first().json.body;
return [{ json: { ...msgs, cliente: data.nome, valor: data.valor, timestamp: new Date().toISOString() } }];
